1	export type Cell = [number, number];
2	
3	const isNeighbor = (cell: Cell, other: Cell): boolean =>
4	  !(other[0] === cell[0] && other[1] === cell[1]) &&
5	  Math.abs(other[0] - cell[0]) <= 1 &&
6	  Math.abs(other[1] - cell[1]) <= 1;
7	
8	const countNeighbors = (cell: Cell, livingCells: Cell[]): number =>
9	  livingCells.filter((other) => isNeighbor(cell, other)).length;
10	
11	export function nextGeneration(livingCells: Cell[]): Cell[] {
12	  return livingCells.filter(
13	    (cell) => {
14	      const neighbors = countNeighbors(cell, livingCells);
15	      return neighbors === 2 || neighbors === 3;
16	    }
17	  );
18	}
